import{c as s,Q as n,j as i,m as e}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"推送通知:APNs、FCM、厂商推送与 token 生命周期","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/13-推送通知.md","filePath":"mobileCommonLearning/13-推送通知.md","lastUpdated":1780912084000}'),p={name:"mobileCommonLearning/13-推送通知.md"};function t(l,a,o,d,r,h){return n(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="推送通知-apns、fcm、厂商推送与-token-生命周期" tabindex="-1">推送通知:APNs、FCM、厂商推送与 token 生命周期 <a class="header-anchor" href="#推送通知-apns、fcm、厂商推送与-token-生命周期" aria-label="Permalink to &quot;推送通知:APNs、FCM、厂商推送与 token 生命周期&quot;">​</a></h1><p>推送不是&quot;服务端发一条消息&quot;。移动推送依赖系统通道、设备 token、权限、厂商服务和 App 状态。</p><p>一句话先记住:<strong>推送 = 用户授权 + 系统通道 + 设备 token + 服务端注册 + 消息策略。</strong></p><hr><h2 id="一、推送链路" tabindex="-1">一、推送链路 <a class="header-anchor" href="#一、推送链路" aria-label="Permalink to &quot;一、推送链路&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App 请求通知权限</span></span>
<span class="line"><span>  -&gt; 系统返回 device token / registration token</span></span>
<span class="line"><span>  -&gt; App 上传 token 到业务后端</span></span>
<span class="line"><span>  -&gt; 后端保存 userId-device-token 关系</span></span>
<span class="line"><span>  -&gt; 后端调用 APNs / FCM / 厂商推送</span></span>
<span class="line"><span>  -&gt; 系统展示通知或唤醒 App</span></span></code></pre></div><p>任何一段断了,用户都收不到。</p><hr><h2 id="二、ios-apns" tabindex="-1">二、iOS APNs <a class="header-anchor" href="#二、ios-apns" aria-label="Permalink to &quot;二、iOS APNs&quot;">​</a></h2><p>iOS 推送走 APNs:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App</span></span>
<span class="line"><span>  -&gt; APNs device token</span></span>
<span class="line"><span>  -&gt; 业务后端</span></span>
<span class="line"><span>  -&gt; APNs</span></span>
<span class="line"><span>  -&gt; 设备</span></span></code></pre></div><p>注意:</p><ul><li>需要通知权限</li><li>Bundle ID 要启用 Push capability</li><li>profile 要包含 aps entitlement</li><li>token 可能变化</li><li>sandbox / production 环境不同</li><li>用户关闭通知后 token 不一定立即失效,但通知不会展示</li></ul><hr><h2 id="三、android-fcm-和厂商推送" tabindex="-1">三、Android FCM 和厂商推送 <a class="header-anchor" href="#三、android-fcm-和厂商推送" aria-label="Permalink to &quot;三、Android FCM 和厂商推送&quot;">​</a></h2><p>海外 Android 常用 FCM。</p><p>国内 Android 需要考虑厂商推送:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>华为 Push Kit</span></span>
<span class="line"><span>小米推送</span></span>
<span class="line"><span>OPPO Push</span></span>
<span class="line"><span>vivo Push</span></span>
<span class="line"><span>荣耀推送</span></span></code></pre></div><p>原因:</p><ul><li>国内很多设备没有 Google Play Services</li><li>后台进程保活受系统限制</li><li>厂商通道到达率更高</li></ul><p>推送聚合平台可以降低接入成本,但仍要理解底层差异。</p><hr><h2 id="四、token-生命周期" tabindex="-1">四、Token 生命周期 <a class="header-anchor" href="#四、token-生命周期" aria-label="Permalink to &quot;四、Token 生命周期&quot;">​</a></h2><p>token 不是永久不变。</p><p>可能变化:</p><ul><li>首次安装</li><li>卸载重装</li><li>用户清数据</li><li>系统或推送服务刷新</li><li>App 恢复备份到新设备</li><li>推送 SDK 变更</li></ul><p>App 每次启动或 token 刷新时要上报:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">registerPushToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  userId,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  token,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  platform,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  appVersion,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  deviceId,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><p>后端要支持同一用户多个设备。</p><hr><h2 id="五、通知类型" tabindex="-1">五、通知类型 <a class="header-anchor" href="#五、通知类型" aria-label="Permalink to &quot;五、通知类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>展示通知</td><td>系统通知栏展示</td></tr><tr><td>静默推送</td><td>不展示,用于后台刷新</td></tr><tr><td>数据消息</td><td>App 自己处理</td></tr><tr><td>本地通知</td><td>App 本地定时展示</td></tr></tbody></table><p>不要把所有消息都当营销推送。系统会惩罚滥用通知的 App。</p><hr><h2 id="六、前台、后台、杀进程" tabindex="-1">六、前台、后台、杀进程 <a class="header-anchor" href="#六、前台、后台、杀进程" aria-label="Permalink to &quot;六、前台、后台、杀进程&quot;">​</a></h2><p>App 状态会影响推送行为:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前台:通常由 App 自己决定是否展示</span></span>
<span class="line"><span>后台:系统展示或唤醒</span></span>
<span class="line"><span>杀进程:平台限制更多</span></span>
<span class="line"><span>省电模式:到达可能延迟</span></span></code></pre></div><p>不要承诺&quot;100% 实时到达&quot;。移动系统不会给你这个保证。</p><hr><h2 id="七、服务端要做什么" tabindex="-1">七、服务端要做什么 <a class="header-anchor" href="#七、服务端要做什么" aria-label="Permalink to &quot;七、服务端要做什么&quot;">​</a></h2><p>后端保存:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>userId</span></span>
<span class="line"><span>token</span></span>
<span class="line"><span>platform</span></span>
<span class="line"><span>appVersion</span></span>
<span class="line"><span>device info</span></span>
<span class="line"><span>createdAt</span></span>
<span class="line"><span>lastSeenAt</span></span>
<span class="line"><span>enabled</span></span></code></pre></div><p>发送后处理:</p><ul><li>token invalid -&gt; 标记失效</li><li>rate limit -&gt; 重试</li><li>payload too large -&gt; 修正</li><li>用户退订 -&gt; 不再发送</li></ul><p>推送系统必须有日志,否则排障靠猜。</p><hr><h2 id="八、什么时候会出事故" tabindex="-1">八、什么时候会出事故 <a class="header-anchor" href="#八、什么时候会出事故" aria-label="Permalink to &quot;八、什么时候会出事故&quot;">​</a></h2><ol><li>iOS entitlements 是 development,生产推送收不到。</li><li>Android 国内设备没 FCM,只接 FCM 到达率很差。</li><li>用户换设备后 token 没更新。</li><li>后端一个用户只存一个 token,多设备互相覆盖。</li><li>用户关闭通知,运营还以为推送通道坏了。</li><li>payload 带敏感信息,锁屏泄漏隐私。</li></ol><hr><h2 id="九、检查清单" tabindex="-1">九、检查清单 <a class="header-anchor" href="#九、检查清单" aria-label="Permalink to &quot;九、检查清单&quot;">​</a></h2><ul><li>[ ] iOS Push capability 是否开启</li><li>[ ] profile 是否包含 aps entitlement</li><li>[ ] sandbox / production 是否区分</li><li>[ ] Android 是否考虑厂商推送</li><li>[ ] token 刷新是否会上报</li><li>[ ] 后端是否支持一人多设备</li><li>[ ] 无效 token 是否清理</li><li>[ ] 推送 payload 是否避免敏感信息</li><li>[ ] 是否有发送日志和到达 / 点击统计</li></ul><hr><h2 id="十、心智模型" tabindex="-1">十、心智模型 <a class="header-anchor" href="#十、心智模型" aria-label="Permalink to &quot;十、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>权限决定能不能展示</span></span>
<span class="line"><span>token 决定发给哪台设备</span></span>
<span class="line"><span>APNs / FCM / 厂商通道决定怎么到达</span></span>
<span class="line"><span>后端 token 表决定能不能持续维护</span></span>
<span class="line"><span>App 状态决定收到后怎么表现</span></span></code></pre></div><p>下一篇 14 讲 Deep Link、Universal Links、App Links 与跳转归因。</p>`,55)])])}const u=s(p,[["render",t]]);export{k as __pageData,u as default};
